  ('optician-moex-00529', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式散光鏡片的動態穩定（dynamicstabilization）設計，下列敘述何者錯誤？', '["眼瞼的作用將使鏡片穩定在正確的方位", "透氧率比其他定位設計低", "高屈光度較適合此設計方式", "屬鏡片上下厚度較薄，中心較厚"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00530', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '驗配軟式鏡片時，關於厚度有一些需要考量的地方，下列敘述何者錯誤？', '["近視度數越重，鏡片中間越薄", "遠視鏡片通常中間厚度較近視鏡片厚", "中心較薄的鏡片，鏡片滑動會比較少", "較厚、高含水鏡片在水蒸發後鏡片會變得更平，所以戴一段時間後要觀察一下鏡片的鬆緊狀況"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00531', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '若驗配硬式隱形眼鏡鏡片直徑為9.00mm，度數為-3.00D，後弧半徑BOZR為8.10mm，鏡片中心定位良好， 有包覆瞳孔，但螢光染色型態中心（centralzone）稍微偏陡，插片驗光（OR）平光為視力1.0，若訂片直徑為', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00532', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '00mm，BOZR為8.15mm，度數BVP要訂多少？', '["-4.00D", "-3.50D", "-3.00D", "-2.75D"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00533', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '若患者鏡架眼鏡為-3.00DS/-3.00DC×180（VD=12mm），應選軟式散光鏡片試戴片為下列何者？', '["-3.00DS/-3.00DC×180", "-3.00DS/-2.50DC×180", "-3.00DS/-3.50DC×180", "-3.00DS/-2.75DC×180"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00534', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '理想的軟式隱形眼鏡驗配，下列敘述何者錯誤？', '["軟式隱形眼鏡驗配應該是舒適的", "軟式隱形眼鏡的定位應該是完全置中，重疊角膜緣至少1mm", "軟式隱形眼鏡驗配在眨眼和類似的視線滯後時，大約會有0.3mm的移動", "軟式隱形眼鏡驗配時，鏡片邊緣與鞏膜貼合需產生結膜壓痕"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00535', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關硬式隱形眼鏡驗配螢光染色的評估，下列敘述何者錯誤？', '["螢光染色的評估對硬式鏡片的驗配，提供了鏡片與眼睛形狀之間有用的資訊", "過量的螢光會干擾鏡片驗配的評估", "螢光染色的評估配合三個主要環形區域做有系統性的評估，包括中央、周邊及邊緣間隙", "對於角膜染色的評估，使用黃色濾鏡對螢光的評估無幫助"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00536', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '硬式隱形眼鏡配戴後出現3和9點鐘方位角膜螢光點狀染色，下列何種不是正確處理方式？', '["增加鏡片邊弧厚度", "鼓勵多完整眨眼", "換成片徑較大之鏡片", "若無法解決，可考慮改成軟式隱形眼鏡"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00537', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '正常眼角膜屈度非正球面，其從中央到周邊變平的程度稱作 e-value（eccentricity value），一般正常角 膜e-value平均值最接近下列何者？', '["0.10～0.30", "0.25～0.35", "0.40～0.50", "0.65～1.0"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00538', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '在使用角膜地形圖儀（keratoscopy或placidodisc）時，當觀察或測量之環狀線間距離愈靠近則代表角膜的 弧度愈：', '["平坦", "陡", "愈不規則", "愈規則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
